changeSet.sql:
CREATE TABLE nexus.chash_index (
    tenant_id           TEXT        NOT NULL,
    chash               TEXT        NOT NULL,
    physical_collection TEXT        NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL,
    CONSTRAINT chash_index_pk PRIMARY KEY (tenant_id, chash, physical_collection)
);

-- idx_chash_index_chash: for lookup() queries by chash
CREATE INDEX idx_chash_index_chash ON nexus.chash_index (tenant_id, chash);

-- idx_chash_index_collection: for delete_collection() and rename_collection() seeks
CREATE INDEX idx_chash_index_collection ON nexus.chash_index (tenant_id, physical_collection);

ALTER TABLE nexus.chash_index ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.chash_index FORCE ROW LEVEL SECURITY;

-- cmd=ALL: covers SELECT, INSERT, UPDATE, DELETE in one policy.
-- USING predicate: filters rows on reads.
-- WITH CHECK predicate: validates rows on writes.
-- current_setting('nexus.tenant', true): missing_ok=true so unset GUC returns NULL
--   rather than raising. NULL != any tenant_id -> zero rows visible = fail-closed.
CREATE POLICY tenant_isolation ON nexus.chash_index
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.chash_index;
ALTER TABLE nexus.chash_index NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.chash_index DISABLE ROW LEVEL SECURITY;

changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.chash_index TO nexus_svc';
        RAISE NOTICE 'Granted nexus.chash_index privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants (create role before first run)';
    END IF;
END
$$;
